   209→/*
   210→ * Parse LDAPResult Messages:
   211→ *
   212→ *   LDAPResult ::= SEQUENCE {
   213→ *     resultCode      ENUMERATED,
   214→ *     matchedDN       LDAPDN,
   215→ *     errorMessage    LDAPString,
   216→ *     referral        [3] Referral OPTIONAL }
   217→ *
   218→ * including Bind results:
   219→ *
   220→ *   BindResponse ::= [APPLICATION 1] SEQUENCE {
   221→ *     COMPONENTS OF LDAPResult,
   222→ *     serverSaslCreds  [7] OCTET STRING OPTIONAL }
   223→ *
   224→ * and ExtendedOp results:
   225→ *
   226→ *   ExtendedResponse ::= [APPLICATION 24] SEQUENCE {
   227→ *     COMPONENTS OF LDAPResult,
   228→ *     responseName     [10] LDAPOID OPTIONAL,
   229→ *     response         [11] OCTET STRING OPTIONAL }
   230→ *
   231→ */
   232→int
   233→ldap_parse_result(
   234→	LDAP			*ld,
   235→	LDAPMessage		*r,
   236→	int				*errcodep,
   237→	char			**matcheddnp,
   238→	char			**errmsgp,
   239→	char			***referralsp,
   240→	LDAPControl		***serverctrls,
   241→	int				freeit )
   242→{
   243→	LDAPMessage	*lm;
   244→	ber_int_t errcode = LDAP_SUCCESS;
   245→
   246→	ber_tag_t tag;
   247→	BerElement	*ber;
   248→
   249→	Debug0( LDAP_DEBUG_TRACE, "ldap_parse_result\n" );
   250→
   251→	assert( ld != NULL );
   252→	assert( LDAP_VALID( ld ) );
   253→	assert( r != NULL );
   254→
   255→	if(errcodep != NULL) *errcodep = LDAP_SUCCESS;
   256→	if(matcheddnp != NULL) *matcheddnp = NULL;
   257→	if(errmsgp != NULL) *errmsgp = NULL;
   258→	if(referralsp != NULL) *referralsp = NULL;
   259→	if(serverctrls != NULL) *serverctrls = NULL;
   260→
   261→	LDAP_MUTEX_LOCK( &ld->ld_res_mutex );
   262→	/* Find the result, last msg in chain... */
   263→	lm = r->lm_chain_tail;
   264→	/* FIXME: either this is not possible (assert?)
   265→	 * or it should be handled */
   266→	if ( lm != NULL ) {
   267→		switch ( lm->lm_msgtype ) {
   268→		case LDAP_RES_SEARCH_ENTRY:
   269→		case LDAP_RES_SEARCH_REFERENCE:
   270→		case LDAP_RES_INTERMEDIATE:
   271→			lm = NULL;
   272→			break;
   273→
   274→		default:
   275→			break;
   276→		}
   277→	}
   278→
   279→	if( lm == NULL ) {
   280→		errcode = ld->ld_errno = LDAP_NO_RESULTS_RETURNED;
   281→		LDAP_MUTEX_UNLOCK( &ld->ld_res_mutex );
   282→	    goto done;
   283→	}
   284→
   285→	if ( ld->ld_error ) {
   286→		LDAP_FREE( ld->ld_error );
   287→		ld->ld_error = NULL;
   288→	}
   289→	if ( ld->ld_matched ) {
   290→		LDAP_FREE( ld->ld_matched );
   291→		ld->ld_matched = NULL;
   292→	}
   293→	if ( ld->ld_referrals ) {
   294→		LDAP_VFREE( ld->ld_referrals );
   295→		ld->ld_referrals = NULL;
   296→	}
   297→
   298→	/* parse results */
   299→
   300→	ber = ber_dup( lm->lm_ber );
   301→
   302→	if ( ld->ld_version < LDAP_VERSION2 ) {
   303→		tag = ber_scanf( ber, "{iA}",
   304→			&ld->ld_errno, &ld->ld_error );
   305→
   306→	} else {
   307→		ber_len_t len;
   308→
   309→		tag = ber_scanf( ber, "{iAA" /*}*/,
   310→			&ld->ld_errno, &ld->ld_matched, &ld->ld_error );
   311→
   312→		if( tag != LBER_ERROR ) {
   313→			/* peek for referrals */
   314→			if( ber_peek_tag(ber, &len) == LDAP_TAG_REFERRAL ) {
   315→				tag = ber_scanf( ber, "v", &ld->ld_referrals );
   316→			}
   317→		}
   318→
   319→		/* need to clean out misc items */
   320→		if( tag != LBER_ERROR ) {
   321→			if( lm->lm_msgtype == LDAP_RES_BIND ) {
   322→				/* look for sasl result credentials */
   323→				if ( ber_peek_tag( ber, &len ) == LDAP_TAG_SASL_RES_CREDS ) {
   324→					/* skip 'em */
   325→					tag = ber_scanf( ber, "x" );
   326→				}
   327→
   328→			} else if( lm->lm_msgtype == LDAP_RES_EXTENDED ) {
   329→				/* look for exop result oid or value */
   330→				if ( ber_peek_tag( ber, &len ) == LDAP_TAG_EXOP_RES_OID ) {
   331→					/* skip 'em */
   332→					tag = ber_scanf( ber, "x" );
   333→				}
   334→
   335→				if ( tag != LBER_ERROR &&
   336→					ber_peek_tag( ber, &len ) == LDAP_TAG_EXOP_RES_VALUE )
   337→				{
   338→					/* skip 'em */
   339→					tag = ber_scanf( ber, "x" );
   340→				}
   341→			}
   342→		}
   343→
   344→		if( tag != LBER_ERROR ) {
   345→			int rc = ldap_pvt_get_controls( ber, serverctrls );
   346→
   347→			if( rc != LDAP_SUCCESS ) {
   348→				tag = LBER_ERROR;
   349→			}
   350→		}
   351→
   352→		if( tag != LBER_ERROR ) {
   353→			tag = ber_scanf( ber, /*{*/"}" );
   354→		}
   355→	}
   356→
   357→	if ( tag == LBER_ERROR ) {
   358→		ld->ld_errno = errcode = LDAP_DECODING_ERROR;
   359→	}
   360→
   361→	if( ber != NULL ) {
   362→		ber_free( ber, 0 );
   363→	}
   364→
   365→	/* return */
   366→	if( errcodep != NULL ) {
   367→		*errcodep = ld->ld_errno;
   368→	}
   369→	if ( errcode == LDAP_SUCCESS ) {
   370→		if( matcheddnp != NULL ) {
   371→			if ( ld->ld_matched )
   372→			{
   373→				*matcheddnp = LDAP_STRDUP( ld->ld_matched );
   374→			}
   375→		}
   376→		if( errmsgp != NULL ) {
   377→			if ( ld->ld_error )
   378→			{
   379→				*errmsgp = LDAP_STRDUP( ld->ld_error );
   380→			}
   381→		}
   382→
   383→		if( referralsp != NULL) {
   384→			*referralsp = ldap_value_dup( ld->ld_referrals );
   385→		}
   386→	}
   387→	LDAP_MUTEX_UNLOCK( &ld->ld_res_mutex );
   388→
   389→done:
   390→	if ( freeit ) {
   391→		ldap_msgfree( r );
   392→	}
   393→
   394→	return errcode;
   395→}
